module node_conv_220 (
    input  wire                       clk,
    input  wire                       rst_n,
    input  wire                       valid_in,
    output wire                       ready_in,
    input  wire [1023:0]              data_in,
    output wire                       valid_out,
    output wire [1023:0]              data_out
);
    localparam integer IC        = 128;
    localparam integer OC        = 128;
    localparam integer IH        = 56;
    localparam integer IW        = 56;
    localparam integer OH        = 28;
    localparam integer OW        = 28;
    localparam integer KH        = 3;
    localparam integer KW        = 3;
    localparam integer SH        = 2;
    localparam integer SW        = 2;
    localparam integer PH        = 1;
    localparam integer PW        = 1;
    localparam integer K_TOTAL   = IC * KH * KW; // 1152
    localparam integer MP        = 8;            // 8 parallel MAC lanes
    localparam integer OC_PASSES = OC / MP;      // 16
    localparam integer SCALE_MULT  = 7687;
    localparam integer SCALE_SHIFT = 23;
    localparam integer EXPECTED_FIRST_OUTPUT_CYCLES = 147708;

    localparam integer PROD_W       = 16;
