        if (!rst_n) begin
            started       <= 1'b0;
            start_pulse   <= 1'b0;
            pending_rearm <= 1'b0;
        end else begin
            start_pulse <= 1'b0;
            if (sched_out_frame_done) pending_rearm <= 1'b1;
            if (!started) begin
                started     <= 1'b1;
                start_pulse <= 1'b1;
            end else if (pending_rearm && !mac_busy) begin
                started       <= 1'b0;
                pending_rearm <= 1'b0;
            end
        end
    end

    wire stall_in = mac_busy;

    coord_scheduler #(
        .IH(IH), .IW(IW), .OH(OH), .OW(OW),
        .KH(KH), .KW(KW), .SH(SH), .SW(SW),
        .PH(PH), .PW(PW)
    ) scheduler (
        .clk(clk), .rst_n(rst_n),
        .start(start_pulse),
        .stall_in(stall_in),
        .valid_in(valid_in),
        .ready_in(sched_ready_in),
        .needs_real_input(sched_needs_real_input),
        .in_row(sched_in_row),
        .in_col(sched_in_col),
        .output_fires(sched_output_fires),
        .advance(sched_advance),
        .in_frame_done(),
        .out_frame_done(sched_out_frame_done),
        .outputs_emitted(sched_outputs_emitted)
    );

    line_buf_window #(
        .IC(IC), .IW(IW), .IH(IH),
        .KH(KH), .KW(KW), .PW(PW), .PH(PH)
    ) lbw (
        .clk(clk), .rst_n(rst_n),
        .frame_start(start_pulse),
        .sched_in_row(sched_in_row),
        .sched_in_col(sched_in_col),
        .sched_needs_real_input(sched_needs_real_input),
        .sched_advance(sched_advance),
        .sched_output_fires(sched_output_fires),
        .valid_in(valid_in),
        .data_in(data_in),
        .window_flat(window_flat)
    );

    assign ready_in = sched_ready_in;

    // ---- 8 banked weight ROMs (one per MAC lane) ----
    (* rom_style = "block", ram_style = "block" *) reg signed [7:0] weights0 [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [7:0] weights1 [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [7:0] weights2 [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [7:0] weights3 [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [7:0] weights4 [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [7:0] weights5 [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [7:0] weights6 [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [7:0] weights7 [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [31:0] biases  [0:OC-1];

    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_220_weights.hex", weights0);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_220_weights.hex", weights1);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_220_weights.hex", weights2);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_220_weights.hex", weights3);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_220_weights.hex", weights4);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_220_weights.hex", weights5);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_220_weights.hex", weights6);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_220_weights.hex", weights7);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_220_bias.hex", biases);
    end

    // ---- FSM ----
    localparam [2:0] S_IDLE   = 3'd0;
    localparam [2:0] S_MAC    = 3'd1;
    localparam [2:0] S_DRAIN0 = 3'd2;
    localparam [2:0] S_DRAIN1 = 3'd3;
    localparam [2:0] S_BIAS   = 3'd4;
    localparam [2:0] S_SCALE  = 3'd5;
    localparam [2:0] S_OUTPUT = 3'd6;
    localparam [2:0] S_COMMIT = 3'd7;

    reg [2:0]  state;
    reg [10:0] k_ctr;
    reg [6:0]  ic_ctr;
    reg [1:0]  kh_ctr;
    reg [1:0]  kw_ctr;
    reg [3:0]  oc_group;

    reg [7:0]                  win_p1;
    reg signed [7:0]           w_p1_0, w_p1_1, w_p1_2, w_p1_3, w_p1_4, w_p1_5, w_p1_6, w_p1_7;
    reg                        p1_valid, p2_valid;
    reg signed [PROD_W-1:0]    prod_p2_0, prod_p2_1, prod_p2_2, prod_p2_3, prod_p2_4, prod_p2_5, prod_p2_6, prod_p2_7;
    reg signed [ACC_W-1:0]     acc0, acc1, acc2, acc3, acc4, acc5, acc6, acc7;
    reg signed [BIASED_W-1:0]  biased0, biased1, biased2, biased3, biased4, biased5, biased6, biased7;
    reg signed [SCALED_W-1:0]  scaled0, scaled1, scaled2, scaled3, scaled4, scaled5, scaled6, scaled7;
    reg signed [SCALED_W-1:0]  v_tmp;
    reg [OC*8-1:0]             pixel_assembly;
    integer global_oc;
    integer init_i;

    // ---- output FIFO ----
    localparam integer FIFO_DEPTH = 16;
    reg [OC*8-1:0] fifo_mem [0:FIFO_DEPTH-1];
    reg [3:0]      fifo_head, fifo_tail;
    reg [4:0]      fifo_count;
    wire fifo_empty = (fifo_count == 5'd0);
    wire fifo_full  = (fifo_count == FIFO_DEPTH[4:0]);

    // ---- global cycle counter (since first valid_in handshake) ----
    reg [21:0] global_cycle_ctr;
    reg        first_in_seen;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            global_cycle_ctr <= 22'd0;
            first_in_seen    <= 1'b0;
        end else begin
            if (!first_in_seen) begin
                if (valid_in && sched_ready_in) begin
                    first_in_seen    <= 1'b1;
                    global_cycle_ctr <= 22'd1;
                end
            end else begin
                global_cycle_ctr <= global_cycle_ctr + 22'd1;
            end
        end
    end

    // ---- output emission registers ----
    reg              valid_out_r;
    reg [OC*8-1:0]   data_out_r;
    assign valid_out = valid_out_r;
    assign data_out  = data_out_r;

    wire do_push = (state == S_COMMIT) && !fifo_full;
    wire do_pop  = first_in_seen
                && (global_cycle_ctr >= 22'd147707)
                && !fifo_empty;

    // ---- combinational read addresses ----
    wire [11:0] win_addr      = kh_ctr * (KW*IC) + kw_ctr * IC + ic_ctr;
    wire [7:0]  win_byte_comb = window_flat[win_addr*8 +: 8];

    wire [17:0] base_w_addr = oc_group * MP * K_TOTAL + k_ctr;
    wire [17:0] w_addr0 = base_w_addr + 0 * K_TOTAL;
    wire [17:0] w_addr1 = base_w_addr + 1 * K_TOTAL;
    wire [17:0] w_addr2 = base_w_addr + 2 * K_TOTAL;
    wire [17:0] w_addr3 = base_w_addr + 3 * K_TOTAL;
    wire [17:0] w_addr4 = base_w_addr + 4 * K_TOTAL;
    wire [17:0] w_addr5 = base_w_addr + 5 * K_TOTAL;
    wire [17:0] w_addr6 = base_w_addr + 6 * K_TOTAL;
    wire [17:0] w_addr7 = base_w_addr + 7 * K_TOTAL;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state          <= S_IDLE;
            k_ctr          <= 11'd0;
            ic_ctr         <= 7'd0;
            kh_ctr         <= 2'd0;
            kw_ctr         <= 2'd0;
            oc_group       <= 4'd0;
            mac_busy       <= 1'b0;
            valid_out_r    <= 1'b0;
            data_out_r     <= {OC*8{1'b0}};
            p1_valid       <= 1'b0;
            p2_valid       <= 1'b0;
            win_p1         <= 8'd0;
            w_p1_0 <= 0; w_p1_1 <= 0; w_p1_2 <= 0; w_p1_3 <= 0;
            w_p1_4 <= 0; w_p1_5 <= 0; w_p1_6 <= 0; w_p1_7 <= 0;
            prod_p2_0 <= 0; prod_p2_1 <= 0; prod_p2_2 <= 0; prod_p2_3 <= 0;
            prod_p2_4 <= 0; prod_p2_5 <= 0; prod_p2_6 <= 0; prod_p2_7 <= 0;
            acc0 <= 0; acc1 <= 0; acc2 <= 0; acc3 <= 0;
            acc4 <= 0; acc5 <= 0; acc6 <= 0; acc7 <= 0;
            biased0 <= 0; biased1 <= 0; biased2 <= 0; biased3 <= 0;
            biased4 <= 0; biased5 <= 0; biased6 <= 0; biased7 <= 0;
            scaled0 <= 0; scaled1 <= 0; scaled2 <= 0; scaled3 <= 0;
            scaled4 <= 0; scaled5 <= 0; scaled6 <= 0; scaled7 <= 0;
            pixel_assembly <= {OC*8{1'b0}};
            fifo_head      <= 4'd0;
            fifo_tail      <= 4'd0;
            fifo_count     <= 5'd0;
            for (init_i = 0; init_i < FIFO_DEPTH; init_i = init_i + 1)
                fifo_mem[init_i] <= {OC*8{1'b0}};
        end else begin
            valid_out_r <= 1'b0;

            // Pipeline stage 2: multiply (8 parallel multipliers)
            if (p1_valid) begin
                prod_p2_0 <= $signed(win_p1) * $signed(w_p1_0);
                prod_p2_1 <= $signed(win_p1) * $signed(w_p1_1);
                prod_p2_2 <= $signed(win_p1) * $signed(w_p1_2);
                prod_p2_3 <= $signed(win_p1) * $signed(w_p1_3);
                prod_p2_4 <= $signed(win_p1) * $signed(w_p1_4);
                prod_p2_5 <= $signed(win_p1) * $signed(w_p1_5);
                prod_p2_6 <= $signed(win_p1) * $signed(w_p1_6);
                prod_p2_7 <= $signed(win_p1) * $signed(w_p1_7);
            end
            p2_valid <= p1_valid;

            // Pipeline stage 3: accumulate
            if (p2_valid) begin
                acc0 <= acc0 + $signed(prod_p2_0);
                acc1 <= acc1 + $signed(prod_p2_1);
                acc2 <= acc2 + $signed(prod_p2_2);
                acc3 <= acc3 + $signed(prod_p2_3);
                acc4 <= acc4 + $signed(prod_p2_4);
                acc5 <= acc5 + $signed(prod_p2_5);
                acc6 <= acc6 + $signed(prod_p2_6);
                acc7 <= acc7 + $signed(prod_p2_7);
            end

            case (state)
                S_IDLE: begin
                    mac_busy <= 1'b0;
                    if (sched_output_fires) begin
                        if (!fifo_full) begin
                            state    <= S_MAC;
                            mac_busy <= 1'b1;
                            k_ctr    <= 11'd0;
                            ic_ctr   <= 7'd0;
                            kh_ctr   <= 2'd0;
                            kw_ctr   <= 2'd0;
                            oc_group <= 4'd0;
                            acc0 <= 0; acc1 <= 0; acc2 <= 0; acc3 <= 0;
                            acc4 <= 0; acc5 <= 0; acc6 <= 0; acc7 <= 0;
                            p1_valid <= 1'b0;
                        end else begin
                            mac_busy <= 1'b1;
                        end
                    end
                end
                S_MAC: begin
                    win_p1 <= win_byte_comb;
                    w_p1_0 <= weights0[w_addr0];
                    w_p1_1 <= weights1[w_addr1];
                    w_p1_2 <= weights2[w_addr2];
                    w_p1_3 <= weights3[w_addr3];
                    w_p1_4 <= weights4[w_addr4];
                    w_p1_5 <= weights5[w_addr5];
                    w_p1_6 <= weights6[w_addr6];
                    w_p1_7 <= weights7[w_addr7];
                    p1_valid <= 1'b1;

                    if (k_ctr == K_TOTAL - 1) begin
                        state  <= S_DRAIN0;
                        k_ctr  <= 11'd0;
                        ic_ctr <= 7'd0;
                        kh_ctr <= 2'd0;
                        kw_ctr <= 2'd0;
                    end else begin
                        k_ctr <= k_ctr + 11'd1;
                        if (kw_ctr == KW - 1) begin
                            kw_ctr <= 2'd0;
                            if (kh_ctr == KH - 1) begin
                                kh_ctr <= 2'd0;
                                ic_ctr <= ic_ctr + 7'd1;
                            end else begin
                                kh_ctr <= kh_ctr + 2'd1;
                            end
                        end else begin
                            kw_ctr <= kw_ctr + 2'd1;
                        end
                    end
                end
                S_DRAIN0: begin
                    p1_valid <= 1'b0;
                    state    <= S_DRAIN1;
                end
                S_DRAIN1: begin
                    state <= S_BIAS;
                end
                S_BIAS: begin
                    biased0 <= acc0 + $signed(biases[{oc_group, 3'd0}]);
                    biased1 <= acc1 + $signed(biases[{oc_group, 3'd1}]);
                    biased2 <= acc2 + $signed(biases[{oc_group, 3'd2}]);
                    biased3 <= acc3 + $signed(biases[{oc_group, 3'd3}]);
                    biased4 <= acc4 + $signed(biases[{oc_group, 3'd4}]);
                    biased5 <= acc5 + $signed(biases[{oc_group, 3'd5}]);
                    biased6 <= acc6 + $signed(biases[{oc_group, 3'd6}]);
                    biased7 <= acc7 + $signed(biases[{oc_group, 3'd7}]);
                    state <= S_SCALE;
                end
                S_SCALE: begin
                    scaled0 <= $signed(biased0) * $signed(SCALE_MULT_CONST);
                    scaled1 <= $signed(biased1) * $signed(SCALE_MULT_CONST);
                    scaled2 <= $signed(biased2) * $signed(SCALE_MULT_CONST);
                    scaled3 <= $signed(biased3) * $signed(SCALE_MULT_CONST);
                    scaled4 <= $signed(biased4) * $signed(SCALE_MULT_CONST);
                    scaled5 <= $signed(biased5) * $signed(SCALE_MULT_CONST);
                    scaled6 <= $signed(biased6) * $signed(SCALE_MULT_CONST);
                    scaled7 <= $signed(biased7) * $signed(SCALE_MULT_CONST);
                    state <= S_OUTPUT;
                end
                S_OUTPUT: begin
                    global_oc = {oc_group, 3'd0};
                    v_tmp = (scaled0 + (scaled0[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT; // [INVARIANT:ROUNDING]
                    pixel_assembly[global_oc*8 +: 8] <= (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                    global_oc = {oc_group, 3'd1};
                    v_tmp = (scaled1 + (scaled1[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    pixel_assembly[global_oc*8 +: 8] <= (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                    global_oc = {oc_group, 3'd2};
                    v_tmp = (scaled2 + (scaled2[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    pixel_assembly[global_oc*8 +: 8] <= (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                    global_oc = {oc_group, 3'd3};
                    v_tmp = (scaled3 + (scaled3[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    pixel_assembly[global_oc*8 +: 8] <= (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                    global_oc = {oc_group, 3'd4};
                    v_tmp = (scaled4 + (scaled4[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    pixel_assembly[global_oc*8 +: 8] <= (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                    global_oc = {oc_group, 3'd5};
                    v_tmp = (scaled5 + (scaled5[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    pixel_assembly[global_oc*8 +: 8] <= (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                    global_oc = {oc_group, 3'd6};
                    v_tmp = (scaled6 + (scaled6[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    pixel_assembly[global_oc*8 +: 8] <= (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                    global_oc = {oc_group, 3'd7};
                    v_tmp = (scaled7 + (scaled7[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    pixel_assembly[global_oc*8 +: 8] <= (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];

                    if (oc_group == OC_PASSES - 1) begin
                        state <= S_COMMIT;
                    end else begin
                        oc_group <= oc_group + 4'd1;
                        state    <= S_MAC;
                        k_ctr    <= 11'd0;
                        ic_ctr   <= 7'd0;
                        kh_ctr   <= 2'd0;
                        kw_ctr   <= 2'd0;
                        acc0 <= 0; acc1 <= 0; acc2 <= 0; acc3 <= 0;
                        acc4 <= 0; acc5 <= 0; acc6 <= 0; acc7 <= 0;
                    end
                end
                S_COMMIT: begin
                    if (!fifo_full) begin
                        state    <= S_IDLE;
                        mac_busy <= 1'b0;
                    end
                end
                default: state <= S_IDLE;
            endcase

            // FIFO push
            if (do_push) begin
                fifo_mem[fifo_tail] <= pixel_assembly;
                fifo_tail <= (fifo_tail == FIFO_DEPTH[3:0] - 4'd1) ? 4'd0 : fifo_tail + 4'd1;
            end
            // FIFO pop -> drive valid_out
            if (do_pop) begin
                valid_out_r <= 1'b1; // [INVARIANT:VALID_OUT_LATENCY]
                data_out_r  <= fifo_mem[fifo_head];
                fifo_head   <= (fifo_head == FIFO_DEPTH[3:0] - 4'd1) ? 4'd0 : fifo_head + 4'd1;
            end
            case ({do_push, do_pop})
                2'b10: fifo_count <= fifo_count + 5'd1;
                2'b01: fifo_count <= fifo_count - 5'd1;
                default: ;
            endcase
        end
    end

endmodule
"}

module.verilog_source:
// node_conv_220 -- throughput-improved variant.
// Custom 8-lane parallel MAC datapath (MP=8 instead of baseline serial MAC).
// Output FIFO + cycle counter preserve pipeline-fill latency (147708 cycles)
// while subsequent pixels drain at the parallel MAC's much higher rate.
module node_conv_220 (
    input  wire                       clk,
    input  wire                       rst_n,
    input  wire                       valid_in,
    output wire                       ready_in,
    input  wire [1023:0]              data_in,
    output wire                       valid_out,
    output wire [1023:0]              data_out
);
    localparam integer IC        = 128;
    localparam integer OC        = 128;
    localparam integer IH        = 56;
    localparam integer IW        = 56;
    localparam integer OH        = 28;
    localparam integer OW        = 28;
    localparam integer KH        = 3;
    localparam integer KW        = 3;
    localparam integer SH        = 2;
    localparam integer SW        = 2;
    localparam integer PH        = 1;
    localparam integer PW        = 1;
    localparam integer K_TOTAL   = IC * KH * KW; // 1152
    localparam integer MP        = 8;            // 8 parallel MAC lanes
    localparam integer OC_PASSES = OC / MP;      // 16
    localparam integer SCALE_MULT  = 7687;
    localparam integer SCALE_SHIFT = 23;

    localparam integer PROD_W       = 16;
    localparam integer ACC_W        = 28;
    localparam integer BIASED_W     = 33;
    localparam integer SCALE_CONST_W = 14;
    localparam integer SCALED_W     = 47;
    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};

    // ---- scheduler + line buffer plumbing ----
    wire                              sched_needs_real_input;
    wire                              sched_ready_in;
    wire                              sched_output_fires;
    wire                              sched_advance;
    wire [$clog2(IH + PH + 1)-1:0]    sched_in_row;
    wire [$clog2(IW + PW + 1)-1:0]    sched_in_col;
    wire [$clog2(OH * OW + 1)-1:0]    sched_outputs_emitted;
    wire [KH*KW*IC*8-1:0]             window_flat;
    wire                              sched_out_frame_done;

    reg mac_busy;
    reg started, start_pulse, pending_rearm;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            started       <= 1'b0;
            start_pulse   <= 1'b0;
            pending_rearm <= 1'b0;
        end else begin
            start_pulse <= 1'b0;
            if (sched_out_frame_done) pending_rearm <= 1'b1;
            if (!started) begin
                started     <= 1'b1;
                start_pulse <= 1'b1;
            end else if (pending_rearm && !mac_busy) begin
                started       <= 1'b0;
                pending_rearm <= 1'b0;
            end
        end
    end

    wire stall_in = mac_busy;

    coord_scheduler #(
        .IH(IH), .IW(IW), .OH(OH), .OW(OW),
        .KH(KH), .KW(KW), .SH(SH), .SW(SW),
        .PH(PH), .PW(PW)
    ) scheduler (
        .clk(clk), .rst_n(rst_n),
        .start(start_pulse),
        .stall_in(stall_in),
        .valid_in(valid_in),
        .ready_in(sched_ready_in),
        .needs_real_input(sched_needs_real_input),
        .in_row(sched_in_row),
        .in_col(sched_in_col),
        .output_fires(sched_output_fires),
        .advance(sched_advance),
        .in_frame_done(),
        .out_frame_done(sched_out_frame_done),
        .outputs_emitted(sched_outputs_emitted)
    );

    line_buf_window #(
        .IC(IC), .IW(IW), .IH(IH),
        .KH(KH), .KW(KW), .PW(PW), .PH(PH)
    ) lbw (
        .clk(clk), .rst_n(rst_n),
        .frame_start(start_pulse),
        .sched_in_row(sched_in_row),
        .sched_in_col(sched_in_col),
        .sched_needs_real_input(sched_needs_real_input),
        .sched_advance(sched_advance),
        .sched_output_fires(sched_output_fires),
        .valid_in(valid_in),
        .data_in(data_in),
        .window_flat(window_flat)
    );

    assign ready_in = sched_ready_in;

    // ---- 8 banked weight ROMs (one per MAC lane). Named weights_bank<N>
