    reg signed [BIASED_W-1:0]  biased0, biased1, biased2, biased3, biased4, biased5, biased6, biased7;
    reg signed [SCALED_W-1:0]  scaled0, scaled1, scaled2, scaled3, scaled4, scaled5, scaled6, scaled7;
    reg signed [SCALED_W-1:0]  v_tmp;
    reg [OC*8-1:0]             pixel_assembly;
    integer global_oc;
    integer init_i;

    // ---- output FIFO ----
    localparam integer FIFO_DEPTH = 16;
    reg [OC*8-1:0] fifo_mem [0:FIFO_DEPTH-1];
    reg [3:0]      fifo_head, fifo_tail;
    reg [4:0]      fifo_count;
    wire fifo_empty = (fifo_count == 5'd0);
