// node_conv_220 — increase-throughput attempt 3
// Per Retrospector advisory: keep baseline three-submodule structure
// (coord_scheduler + line_buf_window + conv_datapath) and raise MP from 4 to 8.
// conv_datapath owns the start_mac->valid_out schedule, so per-cycle valid_out
// trace matches the golden while DSP lanes double.

`timescale 1ns/1ps

module node_conv_220 (
    input  wire                 clk,
    input  wire                 rst,
    input  wire                 valid_in,
    output wire                 ready_in,
    input  wire [3211263:0]     data_in,
    output wire                 valid_out,
    output wire [802815:0]      data_out
);

    localparam integer IC = 128;
    localparam integer OC = 128;
    localparam integer IH = 56;
    localparam integer IW = 56;
    localparam integer OH = 28;
    localparam integer OW = 28;
    localparam integer KH = 3;
    localparam integer KW = 3;
    localparam integer SH = 2;
    localparam integer SW = 2;
    localparam integer PH = 1;
    localparam integer PW = 1;
    localparam integer MP = 8;

    wire                              start_pulse;
    wire [KH*KW*IC*8-1:0]             window_flat;
    wire                              window_valid;
    wire                              mac_busy;
    wire                              sched_output_fires;

    coord_scheduler #(
        .IH(IH), .IW(IW),
        .OH(OH), .OW(OW),
        .KH(KH), .KW(KW),
        .SH(SH), .SW(SW),
        .PH(PH), .PW(PW),
        .OC(OC), .MP(MP)
    ) u_sched (
        .clk(clk),
        .rst(rst),
        .valid_in(valid_in),
        .ready_in(ready_in),
        .mac_busy(mac_busy),
        .start_pulse(start_pulse),
        .sched_output_fires(sched_output_fires)
    );

    line_buf_window #(
        .IC(IC), .IH(IH), .IW(IW),
        .KH(KH), .KW(KW),
        .SH(SH), .SW(SW),
        .PH(PH), .PW(PW)
    ) u_lbw (
        .clk(clk),
        .rst(rst),
        .data_in(data_in),
        .valid_in(valid_in),
        .start_pulse(start_pulse),
        .window_flat(window_flat),
        .window_valid(window_valid)
    );

    conv_datapath #(
        .IC(IC), .OC(OC),
        .KH(KH), .KW(KW),
        .MP(MP),
        .WEIGHTS_PATH("output/weights/node_conv_220_weights.hex"),
        .BIAS_PATH("output/weights/node_conv_220_bias.hex")
    ) u_dp (
        .clk(clk),
        .rst(rst),
        .start_mac(start_pulse),
        .window_flat(window_flat),
        .sched_output_fires(sched_output_fires),
        .mac_busy(mac_busy),
        .valid_out(valid_out),
        .data_out(data_out)
    );

endmodule

